 {"id":"bd-116r","title":"Integration test for long-running agent memory","description":"## Purpose
Integration test simulating long-running agent sessions to verify memory usage stays bounded with the conversation history sliding window.

## Test File Location
`packages/agent-drivers/src/__tests__/long-running-memory.integration.test.ts`

## Test Scenarios

### Scenario 1: Extended Conversation Memory Stability
```typescript
describe("Integration: Long-running agent memory", () => {
  jest.setTimeout(60000);  // 1 minute timeout

  let driver: AcpDriver | ClaudeDriver;
  let initialMemory: number;
  let memorySnapshots: Array<{ messageCount: number; heapUsed: number }> = [];

  beforeEach(() => {
    driver = createRealDriver({
      maxHistoryMessages: 50,
      maxHistoryTokens: 20000,
    });
    global.gc && global.gc();  // Force GC if available
    initialMemory = process.memoryUsage().heapUsed;
    memorySnapshots = [];
    console.log(`[INTEG] Initial heap: ${(initialMemory / 1024 / 1024).toFixed(2)} MB`);
  });

  it("should maintain bounded memory after 200 messages", async () => {
    const session = await driver.createSession({ task: "Memory test" });

    // Simulate 200 messages (4x the limit)
    for (let i = 0; i < 200; i++) {
      // Simulate user message
      await session.addMessage({
        role: "user",
        content: `User message ${i}: ${"x".repeat(100)}`,  // ~100 chars each
      });

      // Simulate assistant response
      await session.addMessage({
        role: "assistant",
        content: `Response ${i}: ${"y".repeat(200)}`,  // ~200 chars each
      });

      // Snapshot memory every 20 messages
      if (i % 20 === 0) {
        global.gc && global.gc();
        const currentMemory = process.memoryUsage().heapUsed;
        memorySnapshots.push({
          messageCount: i,
          heapUsed: currentMemory,
        });
        console.log(
          `[INTEG] Message ${i}: heap=${(currentMemory / 1024 / 1024).toFixed(2)} MB, ` +
          `history=${session.conversationHistory.length}`
        );
      }
    }

    // Final memory check
    global.gc && global.gc();
    const finalMemory = process.memoryUsage().heapUsed;
    const memoryDelta = finalMemory - initialMemory;

    console.log(`[INTEG] Final heap: ${(finalMemory / 1024 / 1024).toFixed(2)} MB`);
    console.log(`[INTEG] Memory delta: ${(memoryDelta / 1024 / 1024).toFixed(2)} MB`);

    // Assertions
    // 1. History should be bounded
    expect(session.conversationHistory.length).toBeLessThanOrEqual(51);  // system + 50
    console.log(`[INTEG] Final history length: ${session.conversationHistory.length}`);

    // 2. Memory should not have grown linearly
    // With 200 messages at ~300 chars each, unbounded would be ~60KB of content
    // With bounding, should be ~15KB (50 messages)
    expect(memoryDelta).toBeLessThan(10 * 1024 * 1024);  // < 10 MB growth
    console.log("[INTEG] PASS: Memory delta under 10MB threshold");

    // 3. Memory should not be growing linearly with message count
    const earlyMemory = memorySnapshots[2]?.heapUsed || initialMemory;
    const lateMemory = memorySnapshots[memorySnapshots.length - 1]?.heapUsed || finalMemory;
    const memoryGrowthRate = (lateMemory - earlyMemory) / (200 - 40);

    console.log(`[INTEG] Memory growth rate: ${(memoryGrowthRate / 1024).toFixed(2)} KB/message`);
    expect(memoryGrowthRate).toBeLessThan(1024);  // < 1KB per message average
    console.log("[INTEG] PASS: Memory growth rate is sublinear");
  });

  it("should preserve system message after heavy pruning", async () => {
    const systemContent = "CRITICAL: Always respond in JSON format";
    const session = await driver.createSession({ 
      task: "System message test",
      systemPrompt: systemContent,
    });

    // Add many messages to force aggressive pruning
    for (let i = 0; i < 100; i++) {
      await session.addMessage({ role: "user", content: `Message ${i}` });
    }

    // Verify system message preserved
    expect(session.conversationHistory[0].role).toBe("system");
    expect(session.conversationHistory[0].content).toContain("CRITICAL");
    console.log("[INTEG] PASS: System message preserved after 100 messages");
  });

  it("should not lose recent context after pruning", async () => {
    const session = await driver.createSession({ task: "Context test" });

    // Add specific messages we want to verify are kept
    for (let i = 0; i < 60; i++) {
      await session.addMessage({ 
        role: "user", 
        content: `User query ${i}` 
      });
      await session.addMessage({ 
        role: "assistant", 
        content: i >= 50 ? `RECENT_RESPONSE_${i}` : `Old response ${i}` 
      });
    }

    // Most recent messages should be kept
    const contents = session.conversationHistory.map(m => m.content);
    expect(contents).toContain("RECENT_RESPONSE_59");
    expect(contents).toContain("RECENT_RESPONSE_58");

    // Old messages should be pruned
    expect(contents).not.toContain("Old response 0");
    expect(contents).not.toContain("Old response 10");

    console.log("[INTEG] PASS: Recent context preserved, old pruned");
  });
});
```

### Scenario 2: Multi-Session Memory Isolation
```typescript
describe("Integration: Multi-session memory isolation", () => {
  it("should not leak memory between sessions", async () => {
    const driver = createRealDriver({ maxHistoryMessages: 20 });

    global.gc && global.gc();
    const beforeSessions = process.memoryUsage().heapUsed;

    // Create and destroy 10 sessions
    for (let s = 0; s < 10; s++) {
      const session = await driver.createSession({ task: `Session ${s}` });

      // Fill session with messages
      for (let i = 0; i < 50; i++) {
        await session.addMessage({ role: "user", content: `S${s}-M${i}` });
      }

      // Destroy session
      await driver.destroySession(session.id);
      console.log(`[INTEG] Session ${s} created, filled, destroyed`);
    }

    global.gc && global.gc();
    const afterSessions = process.memoryUsage().heapUsed;
    const leak = afterSessions - beforeSessions;

    console.log(`[INTEG] Memory before: ${(beforeSessions / 1024 / 1024).toFixed(2)} MB`);
    console.log(`[INTEG] Memory after: ${(afterSessions / 1024 / 1024).toFixed(2)} MB`);
    console.log(`[INTEG] Potential leak: ${(leak / 1024 / 1024).toFixed(2)} MB`);

    // Should not have significant memory retained after session destruction
    expect(leak).toBeLessThan(5 * 1024 * 1024);  // < 5 MB
    console.log("[INTEG] PASS: No significant memory leak between sessions");
  });
});
```

### Scenario 3: Token Counter Performance
```typescript
describe("Integration: Token counting performance", () => {
  it("should count tokens efficiently for pruning decisions", async () => {
    const driver = createRealDriver({ 
      maxHistoryMessages: 1000,
      maxHistoryTokens: 10000,  // Token limit will trigger first
    });

    const session = await driver.createSession({ task: "Token test" });
    const startTime = performance.now();

    // Add messages until token limit triggers
    for (let i = 0; i < 100; i++) {
      await session.addMessage({
        role: "user",
        content: "x".repeat(500),  // ~125 tokens each
      });
    }

    const elapsed = performance.now() - startTime;
    console.log(`[INTEG] 100 messages with token counting: ${elapsed.toFixed(2)} ms`);

    // Token counting + pruning should be fast
    expect(elapsed).toBeLessThan(5000);  // < 5 seconds for 100 messages

    // Verify token limit was enforced
    const estimatedTokens = session.conversationHistory.reduce(
      (sum, m) => sum + Math.ceil((m.content as string).length / 4),
      0
    );
    console.log(`[INTEG] Estimated remaining tokens: ${estimatedTokens}`);
    expect(estimatedTokens).toBeLessThanOrEqual(12000);  // Some buffer
  });
});
```

